head.script:
scwin.g_sUserId = "";
scwin.vAuthYn = "N";
scwin.closeYm = "";
scwin.stdYm = "";

scwin.onpageload = function() {
    scwin.g_sUserId = $c.ses.getEmpNo();
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strStdDt = scwin.vCurDate.substring(0, 6);

    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        scwin.closeYm = scwin.params["closeYm"] || "";
        scwin.stdYm = scwin.params["stdYm"] || "";
    }

    ds_search.set("clsCd", "2");
    ed_closeYm.setValue(scwin.strStdDt);

    scwin.f_befMonth();

    lc_crcCd.setValue("USD");

    $c.gus.cfDisableObjects([ed_stdYm]);

    scwin.f_getRamt();
    scwin.f_retrieveAuth();
};

scwin.sbm_retrieveAuth_submitdone = async function(e) {
    if (ds_auth.getRowCount() != 0) {
        $c.gus.cfEnableObjects([btn_saveRamt, lc_ramtCrcCd, ed_ramt]);
        scwin.vAuthYn = "Y";
    } else {
        $c.gus.cfDisableObjects([btn_saveRamt, lc_ramtCrcCd, ed_ramt]);
        scwin.vAuthYn = "N";
    }

    if (scwin.closeYm.trim() != "") {
        ed_closeYm.setValue(scwin.closeYm);
        ed_stdYm.setValue(scwin.stdYm);
        scwin.f_Retrieve();
        $c.gus.cfDisableObjects([btn_save, btn_saveRamt]);
    }
};

scwin.sbm_retrieveAuth_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_retrieveAuth = async function() {
    let action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
        + "&queryId=retrieveBorrowAcqKindInfo&param1=IL110" + "&param2=" + scwin.g_sUserId;
    sbm_retrieveAuth.action = action;
    await $c.sbm.execute(sbm_retrieveAuth);
};

scwin.f_befMonth = function() {
    let closeYm = ed_closeYm.getValue();

    let year = parseInt(closeYm.substring(0, 4), 10);
    let month = parseInt(closeYm.substring(4, 6), 10);

    let firstDayOfMonth = new Date(year, month - 1, 1);

    firstDayOfMonth.setDate(firstDayOfMonth.getDate() - 1);
    let lastMonth = firstDayOfMonth;

    let vStdYm = lastMonth.getFullYear() + ("0" + (lastMonth.getMonth() + 1)).slice(-2);

    ed_stdYm.setValue(vStdYm);
};

scwin.getLastDayOfMonth = function() {
    let stdYmVal = ed_stdYm.getValue();
    let year = stdYmVal.substring(0, 4);
    let month = stdYmVal.substring(4, 6);
    let date = new Date(year, month, 0);
    let lastDt = date.getDate();

    if (lastDt == 31) {
        gr_masterList.setColumnVisible("amt29d", true);
        gr_masterList.setColumnVisible("amt30d", true);
        gr_masterList.setColumnVisible("amt31d", true);
    } else if (lastDt == 30) {
        gr_masterList.setColumnVisible("amt29d", true);
        gr_masterList.setColumnVisible("amt30d", true);
        gr_masterList.setColumnVisible("amt31d", false);
    } else if (lastDt == 29) {
        gr_masterList.setColumnVisible("amt29d", true);
        gr_masterList.setColumnVisible("amt30d", false);
        gr_masterList.setColumnVisible("amt31d", false);
    } else if (lastDt == 28) {
        gr_masterList.setColumnVisible("amt29d", false);
        gr_masterList.setColumnVisible("amt30d", false);
        gr_masterList.setColumnVisible("amt31d", false);
    }
};

scwin.f_getRamt = async function() {
    let vStdYm = ed_stdYm.getValue();
    let vCrcCD = lc_ramtCrcCd.getValue();

    let param1 =
        " STD_YM  as COL1 "
        + ",CRC_CD  as COL2 "
        + ",RAMT    as COL3 "
        + ",'' 		as COL4 "
        + ",'' 		as COL5 "
        + ",'' 		as COL6 "
        + ",''      as COL7 "
        + ",''      as COL8 "
        + ",''      as COL9 "
        + ",''      as COL10";

    let param2 = " TB_FM407 ";

    let param3 =
        " AND STD_YM = '" + vStdYm + "'"
        + " AND CRC_CD = '" + vCrcCD + "'";

    let param4 = "STD_YM";

    let action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest"
        + "&param1=" + encodeURIComponent(param1)
        + "&param2=" + encodeURIComponent(param2)
        + "&param3=" + encodeURIComponent(param3)
        + "&param4=" + encodeURIComponent(param4);
    sbm_retrieveRamt.action = action;
    await $c.sbm.execute(sbm_retrieveRamt);
};

scwin.sbm_retrieveRamt_submitdone = function(e) {
    if (ds_temp.getRowCount() != 0) {
        ds_fcrcRamt.set("stdYm", ds_temp.getCellData(0, "col1"));
        ds_fcrcRamt.set("crcCd", ds_temp.getCellData(0, "col2"));
        ds_fcrcRamt.set("ramt", ds_temp.getCellData(0, "col3"));
    } else {
        ds_fcrcRamt.set("ramt", 0);
    }
};

scwin.sbm_retrieveRamt_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_openPopUp = function(orgObjCd, orgObjNm, select_code, flag) {
    let rtnList = new Array();
    let cd = "";
    let nm = "";
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }

    switch (select_code) {
        case '1':
            break;
        case '2':
            let param = "000";
            rtnList = $c.gus.cfCommonPopUp('retrieveClntEmpNoList', cd, nm, "T", null, null, null, null, null, null, null, null, null);
            scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);
            break;
        case '3':
            rtnList = $c.gus.cfCommonPopUp('retrieveAcEmpInfo', cd, nm, "T", null, null, null, null, null, null, null, null, null);
            scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);
            break;
    }
};

scwin.f_CheckPopUp = function(orgObjCd, orgObjNm, select_code, flag) {
    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.hidVal = "";
    }
};

scwin.f_resultPopUp = function(orgObjCd, orgObjNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            orgObjCd.setValue("");
            orgObjNm.setValue("");
            orgObjCd.hidVal = "";
            orgObjNm.hidVal = "";
            return;
        }
        orgObjCd.setValue(rtnList[0]);
        orgObjNm.setValue(rtnList[1]);
        orgObjCd.hidVal = rtnList[0];
        orgObjNm.hidVal = rtnList[1];
    } else {
        orgObjCd.setValue("");
        orgObjNm.setValue("");
        orgObjCd.hidVal = "";
        orgObjNm.hidVal = "";
    }
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;
    let row = ds_additionalValue.getRowPosition();

    switch (disGubun) {
        case 1:
            break;

        case 2:
            let param = ",,,000";
            pCode = ds_additionalValue.getCellData(row, "clntNo");

            rtnList = $c.gus.cfCommonPopUp('retrieveClntList', pCode, '', pClose, null, null, null, "3,4,5,6,7,8,9,10", param, null, null, null, null, null, null, null);
            if (rtnList != null) {
                if (rtnList[0] == "N/A") return false;

                ds_additionalValue.setCellData(row, "clntNo", rtnList[0]);
                ds_additionalValue.setCellData(row, "clntNm", rtnList[1]);
            }
            break;
    }
};

scwin.f_GridToExcel = async function(gridObj, gridName) {
    if (ds_masterList.getRowCount() <= 0) {
        await $c.win.alert("내역이 존재하지않습니다.");
        return false;
    }

    $c.data.downloadGridViewExcel(gridObj, {"fileName": gridName + ".xlsx", "sheetName": gridName});
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([ed_stdYm]);
    if (!chk) return false;

    lc_ramtCrcCd.setValue(lc_crcCd.getValue());
    scwin.f_getRamt();
    await $c.sbm.execute(sbm_retrieve);
    await $c.sbm.execute(sbm_retrieveAdditionalValue);
};

scwin.f_Save = async function() {
    if (ds_fcrcRamt.get("stdYm") == "" && ds_fcrcRamt.get("crcCd") == "" && ds_fcrcRamt.get("ramt") == "") {
        await $c.win.alert("데이타가 없습니다.");
        return;
    }

    if (ds_fcrcRamt.get("stdYm") == "") {
        ds_fcrcRamt.set("stdYm", ed_stdYm.getValue());
    }

    if (ds_fcrcRamt.get("crcCd") == "") {
        await $c.win.alert("환종을 선택하세요.");
        return;
    }

    if (ds_fcrcRamt.isUpdated() == false) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    await $c.sbm.execute(sbm_save);
};

scwin.f_Add = function() {
    $c.data.insertRow(ds_additionalValue);
    let row = ds_additionalValue.getRowPosition();

    ds_additionalValue.setCellData(row, "crcCd", "USD");
    ds_additionalValue.setCellData(row, "clsCd", "2");
};

scwin.f_Delete = function() {
    let row = ds_additionalValue.getRowPosition();
    if (row >= 0) {
        ds_additionalValue.removeRow(row);
    }
};

scwin.f_Cancel = function() {
    let row = ds_additionalValue.getRowPosition();
    if (row >= 0) {
        ds_additionalValue.undoRow(row);
    }
};

scwin.f_SaveAdditionalValue = async function() {
    let chk = await $c.gus.cfValidate([gr_additionalValue]);
    if (!chk) return false;

    if (ds_additionalValue.getRowCount() == 0) {
        await $c.win.alert("데이타가 없습니다.");
        return;
    }

    if (ds_additionalValue.isUpdated() == false) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (let i = 0; i < ds_additionalValue.getRowCount(); i++) {
        let vStdDt = ds_additionalValue.getCellData(i, "stdDt").substring(0, 6);

        if (vStdDt != ed_stdYm.getValue()) {
            await $c.win.alert((i + 1) + "행의 날짜는 기준년월의 월과 같아야 합니다.");
            return;
        }

        if (ds_additionalValue.getCellData(i, "additionalKndCd") == "") {
            await $c.win.alert((i + 1) + "행의 구분값을 입력하세요");
            return;
        }
    }

    await $c.sbm.execute(sbm_saveAdditionalValue);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    scwin.getLastDayOfMonth();

    if (ds_masterList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
    spa_totalRow.setValue(ds_masterList.getRowCount());
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveAdditionalValue_submitdone = function(e) {
    spa_totalRow2.setValue(ds_additionalValue.getRowCount());
};

scwin.sbm_retrieveAdditionalValue_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_saveAdditionalValue_submitdone = async function(e) {
    await $c.win.alert("추가값이 저장되었습니다.");
    scwin.f_Retrieve();
};

scwin.sbm_saveAdditionalValue_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg("기초잔액이 저장되었습니다.");
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_saveRamt_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_addItem_onclick = function(e) {
    scwin.f_Add();
};

scwin.btn_deleteItem_onclick = function(e) {
    scwin.f_Delete();
};

scwin.btn_cancelItem_onclick = function(e) {
    scwin.f_Cancel();
};

scwin.btn_save_onclick = function(e) {
    scwin.f_SaveAdditionalValue();
};

scwin.gr_additionalValue_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (ds_additionalValue.getRowStatus(rowIndex) == "C") {
        gr_additionalValue.setColumnReadOnly("additionalKndCd", false);
        gr_additionalValue.setColumnReadOnly("crcCd", false);
        gr_additionalValue.setColumnReadOnly("stdDt", false);
        gr_additionalValue.setColumnReadOnly("clntNo", false);
    } else {
        gr_additionalValue.setColumnReadOnly("additionalKndCd", true);
        gr_additionalValue.setColumnReadOnly("crcCd", true);
        gr_additionalValue.setColumnReadOnly("stdDt", false);
        gr_additionalValue.setColumnReadOnly("clntNo", true);
    }

    if (columnId == "additionalKndCd") {
        if (ds_additionalValue.getCellData(rowIndex, "gubun") == "1") {
        } else {
        }
    }
};

scwin.gr_additionalValue_ontextimageclick = function(rowIndex, columnIndex) {
    let columnId = gr_additionalValue.getColumnID(columnIndex);
    if (columnId == "clntNo") {
        scwin.f_openCommonPopUp(2, '', '', 'T', 'T');
    } else if (columnId == "stdDt") {
        // TODO: cfOpenCalendar for grid calendar - handled by inputType="calendar"
    }
};

scwin.ds_additionalValue_oncelldatachange = function(info) {
    let row = info.row;
    let colid = info.colId;

    if (colid == "clntNo") {
        scwin.f_openCommonPopUp(2, '', '', 'T', 'T');
    }
    if (colid == "additionalKndCd") {
        let kndCd = ds_additionalValue.getCellData(row, "additionalKndCd");
        if (kndCd == "1" || kndCd == "2" || kndCd == "3") {
            ds_additionalValue.setCellData(row, "gubun", "1");
        } else if (kndCd == "4" || kndCd == "5") {
            ds_additionalValue.setCellData(row, "gubun", "2");
        }
    }
};

scwin.lc_ramtCrcCd_onchange = function(e) {
    scwin.f_getRamt();
};

scwin.ed_closeYm_onchange = function(e) {
    scwin.f_befMonth();
};

scwin.onUdcCompleted = async function() {
    let codeOptions = [
        { grpCd: "ZZ006", compID: "lc_crcCd,lc_ramtCrcCd,gr_additionalValue:crcCd" },
        { grpCd: "IL111", compID: "gr_additionalValue:gubun" },
        { grpCd: "IL112", compID: "gr_additionalValue:additionalKndCd" }
    ];
    await $c.data.setCommonCode(codeOptions);
    lc_crcCd.getSelectedIndex(1);
};
